export function TechMarquee() {
  const trackRef = useRef(null);
  // Tripled so we can wrap seamlessly while dragging in either direction.
  const items = [...TECHNOLOGIES, ...TECHNOLOGIES, ...TECHNOLOGIES];

  useEffect(() => {
    const track = trackRef.current;
    if (!track) return;

    const SPEED = 0.5; // auto-scroll, px per frame
    const reduceMotion = window.matchMedia(
      "(prefers-reduced-motion: reduce)",
    ).matches;

    let offset = 0;
    let copyWidth = track.scrollWidth / 3;
    let hovered = false;
    let dragging = false;
    let startX = 0;
    let startOffset = 0;
    let lastX = 0;
    let velocity = 0;
    let raf = 0;
    let glideRaf = 0;

    // Start one copy in, so there's room to drag backwards immediately.
    offset = copyWidth;

    const measure = () => {
      copyWidth = track.scrollWidth / 3;
    };

    const wrap = () => {
      if (copyWidth <= 0) return;
      while (offset >= copyWidth * 2) offset -= copyWidth;
      while (offset < copyWidth) offset += copyWidth;
    };

    const apply = () => {
      track.style.transform = `translate3d(${-offset}px, 0, 0)`;
    };

    const tick = () => {
      if (!hovered && !dragging && !reduceMotion) offset += SPEED;
      wrap();
      apply();
      raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);

    const onEnter = () => {
      hovered = true;
    };
    const onLeave = () => {
      hovered = false;
    };

    const onDown = (e) => {
      cancelAnimationFrame(glideRaf);
      dragging = true;
      startX = lastX = e.clientX;
      startOffset = offset;
      velocity = 0;
      track.style.cursor = "grabbing";
      track.setPointerCapture?.(e.pointerId);
    };

    const onMove = (e) => {
      if (!dragging) return;
      velocity = e.clientX - lastX;
      lastX = e.clientX;
      offset = startOffset - (e.clientX - startX);
      wrap();
      apply();
    };

    const onUp = () => {
      if (!dragging) return;
      dragging = false;
      track.style.cursor = "grab";
      // Momentum: keep gliding, decaying, until it settles.
      let v = velocity;
      const glide = () => {
        if (dragging || Math.abs(v) < 0.3) return;
        offset -= v;
        v *= 0.94;
        wrap();
        apply();
        glideRaf = requestAnimationFrame(glide);
      };
      glide();
    };

    measure();
    apply();
    window.addEventListener("resize", measure);
    track.addEventListener("pointerenter", onEnter);
    track.addEventListener("pointerleave", onLeave);
    track.addEventListener("pointerdown", onDown);
    track.addEventListener("pointermove", onMove);
    track.addEventListener("pointerup", onUp);
    track.addEventListener("pointercancel", onUp);

    return () => {
      cancelAnimationFrame(raf);
      cancelAnimationFrame(glideRaf);
      window.removeEventListener("resize", measure);
      track.removeEventListener("pointerenter", onEnter);
      track.removeEventListener("pointerleave", onLeave);
      track.removeEventListener("pointerdown", onDown);
      track.removeEventListener("pointermove", onMove);
      track.removeEventListener("pointerup", onUp);
      track.removeEventListener("pointercancel", onUp);
    };
  }, []);

  return (
    <section className="relative overflow-hidden border-y border-border bg-card/20 py-12">
      <motion.div
        className="mx-auto mb-8 max-w-6xl px-6 text-center"
        initial={{ opacity: 0, y: 30 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ duration: 0.6 }}
      >
        <div className="brand-label mb-4">Stack</div>
        <h2 className="font-display text-3xl font-black text-foreground md:text-4xl">
          Tecnologias que utilizamos
        </h2>
      </motion.div>

      {/* edge fades */}
      <div className="pointer-events-none absolute inset-y-0 left-0 z-10 w-12 bg-gradient-to-r from-background to-transparent md:w-24" />
      <div className="pointer-events-none absolute inset-y-0 right-0 z-10 w-12 bg-gradient-to-l from-background to-transparent md:w-24" />

      <div className="mask-gradient w-full overflow-hidden py-4">
        <div
          ref={trackRef}
          className="flex w-max cursor-grab touch-pan-y select-none items-center [will-change:transform]"
        >
          {items.map((tech, i) => (
            <TechItem key={`${tech.name}-${i}`} {...tech} />
          ))}
        </div>
      </div>
    </section>
  );
}
